diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..f1f6bd102796 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -2029,8 +2029,42 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
     // C-(C2-X) --> X+(C-C2)
     if (match(Op1, m_Sub(m_ImmConstant(C2), m_Value(X))))
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
+
+    // C-((C1-X) & Mask) --> X & Mask
+    // where C = C1 & Mask, and the low bits of C1 (the bits cleared by Mask)
+    // are all 1, so that (C1-X) does not borrow from the masked bits.
+    // Requires nuw on the inner sub to ensure C1 >= X.
+    const APInt *C1, *Mask;
+    if (match(Op1, m_OneUse(m_And(m_Sub(m_APInt(C1), m_Value(X)),
+                                   m_APInt(Mask))))) {
+      if (auto *InnerSub = dyn_cast<BinaryOperator>(
+              cast<Instruction>(Op1)->getOperand(0))) {
+        if (InnerSub->getOpcode() == Instruction::Sub &&
+            InnerSub->hasNoUnsignedWrap()) {
+          const APInt *SubC;
+          if (match(Op0, m_APInt(SubC))) {
+            APInt LowBits = ~*Mask;
+            // Check: C == C1 & Mask
+            if (*SubC == (*C1 & *Mask) &&
+                // Check: low bits of C1 are all 1
+                (*C1 & LowBits) == LowBits) {
+              // Compute the narrowed mask: given nuw, X <= C1, so bits
+              // above the highest bit of C1 are known zero.
+              unsigned BitWidth = I.getType()->getScalarSizeInBits();
+              APInt ResultMask = *Mask;
+              if (C1->getActiveBits() > 0)
+                ResultMask &= APInt::getLowBitsSet(BitWidth,
+                                                   C1->getActiveBits());
+              return BinaryOperator::CreateAnd(
+                  X, ConstantInt::get(I.getType(), ResultMask));
+            }
+          }
+        }
+      }
+    }
   }

+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
